class Solution:
    def connectTwoGroups(self, cost):
        size1 = len(cost)
        size2 = len(cost[0])
        full = (1 << size2) - 1
        min_col = [min(cost[r][j] for r in range(size1)) for j in range(size2)]
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def dp(i, mask):
            if i == size1:
                return sum(min_col[j] for j in range(size2) if not (mask & (1 << j)))
            best = min(
                cost[i][j] + dp(i + 1, mask | (1 << j))
                for j in range(size2)
            )
            return best

        result = dp(0, 0)
        dp.cache_clear()
        return result

