var connectTwoGroups = function(cost) {
    const size1 = cost.length;
    const size2 = cost[0].length;
    const minCol = new Array(size2).fill(Infinity);
    for (let j = 0; j < size2; j++) {
        for (let r = 0; r < size1; r++) {
            if (cost[r][j] < minCol[j]) minCol[j] = cost[r][j];
        }
    }
    const memo = new Map();
    const dp = (i, mask) => {
        if (i === size1) {
            let extra = 0;
            for (let j = 0; j < size2; j++) {
                if (!(mask & (1 << j))) extra += minCol[j];
            }
            return extra;
        }
        const key = i * (1 << size2) + mask;
        if (memo.has(key)) return memo.get(key);
        let best = Infinity;
        for (let j = 0; j < size2; j++) {
            const v = cost[i][j] + dp(i + 1, mask | (1 << j));
            if (v < best) best = v;
        }
        memo.set(key, best);
        return best;
    };
    return dp(0, 0);
};
